@Test
public void testStartTagWithNameOnly() {
    String html = "<div><p>Test</p></div>";
    Document doc = Jsoup.parse(html);
    assertEquals("Test", doc.select("p").text());
    assertEquals("div", doc.body().child(0).tagName());
}

@Test
public void testEndTagProcessing() {
    String html = "<div><span>Content</span></div>";
    Document doc = Jsoup.parse(html);
    Elements spans = doc.select("span");
    assertEquals(1, spans.size());
    assertEquals("Content", spans.first().text());
}

@Test
public void testNestedTagsWithAttributes() {
    String html = "<table><tr><td class='test'>Cell</td></tr></table>";
    Document doc = Jsoup.parse(html);
    Element td = doc.select("td").first();
    assertNotNull(td);
    assertEquals("test", td.attr("class"));
    assertEquals("Cell", td.text());
}
